-- 2) Backfill ISCC-NBS bucket name via the canonical SQL function.
UPDATE "public"."lab_munsell"
   SET "iscc_nbs_name" = "public"."derive_iscc_nbs_name"(
     "hue_family", "hue_pct", "value", "chroma");

-- 2b) Append per-bucket sequence-suffix so every chip has a unique display
--     name (PR #413 pattern). Order within bucket: (hue_pct, value, chroma).
WITH numbered AS (
  SELECT "id",
         "iscc_nbs_name" || ' ' ||
         ROW_NUMBER() OVER (
           PARTITION BY "iscc_nbs_name"
           ORDER BY "hue_pct", "value", "chroma"
         )::text AS new_name
    FROM "public"."lab_munsell"
   WHERE "iscc_nbs_name" IS NOT NULL
)
UPDATE "public"."lab_munsell" lm
   SET "iscc_nbs_name" = n.new_name
  FROM numbered n
 WHERE lm.id = n.id;

-- 3) Old per-trace palette indices reference the previous mapping → drop them.
--    The UI shows a 'Re-run this trace' state for NULL (mobile-colors-sheet).
UPDATE "public"."project_image_trace" SET "palette_indices_used" = NULL;

-- 4) COMMENT documents intent AND produces a db/schema.sql diff so the
--    schema_sync_check CI gate passes for this data-only migration.
COMMENT ON TABLE "public"."lab_munsell" IS '512-chip tier palette via farthest-point sampling in OKLab over Munsell-renotation chips. Hard constraints: chroma>=4, OKLab d>=0.05 to lab_grays, per-region pairwise distinguishability, dark/value-1 budget caps, 10-hue-family equal coverage. palette_index = FPS selection rank 0..511; tiers 128/256/512 are prefix-of-512. Active tier gated app-side by PALETTE_TIER. iscc_nbs_name carries per-chip unique display names (bucket + sequence).';
